const channels = ['facebook', 'google_ads', 'instagram', 'linkedin'];
const today = new Date().toISOString().split('T')[0];

const records = channels.map(channel => ({
  date: today,
  channel,
  impressions: Math.floor(Math.random() * 20000) + 1000,
  clicks: Math.floor(Math.random() * 500) + 50,
  spend: Math.floor(Math.random() * 10000) + 1000,
  leads_generated: Math.floor(Math.random() * 15) + 1,
  conversions: Math.floor(Math.random() * 3),
  is_mock: true,
  metadata: { source: 'n8n_analytics_collector', region: 'Bangalore' }
}));

return records.map(r => {
  r.ctr = r.impressions > 0 ? +(r.clicks / r.impressions * 100).toFixed(2) : 0;
  r.cpl = r.leads_generated > 0 ? +(r.spend / r.leads_generated).toFixed(2) : 0;
  return { json: r };
});
